css:
.rt-doc{font-family:'Helvetica Neue',Arial,sans-serif;color:#15212B;font-size:12px}
.rt-top{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #E8593E;padding-bottom:12px;margin-bottom:18px}
.rt-co{font-size:20px;font-weight:700}
.rt-co small{display:block;font-weight:400;color:#6B6256;font-size:11px;margin-top:2px}
.rt-title{text-align:right}
.rt-title h2{margin:0;font-size:16px;letter-spacing:.08em;text-transform:uppercase;color:#15212B}
.rt-title .ref{color:#6B6256;font-size:11px;margin-top:3px}
.rt-cols{display:flex;gap:24px;margin-bottom:16px}
.rt-cols>div{flex:1}
.rt-h{font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:#2E7D74;font-weight:700;margin-bottom:5px;border-bottom:1px solid #E3D8C6;padding-bottom:3px}
.rt-kv{margin:3px 0}.rt-kv b{display:inline-block;min-width:120px;color:#6B6256;font-weight:600}
table.rt-tbl{width:100%;border-collapse:collapse;margin:8px 0 14px}
table.rt-tbl th{background:#F3EBDD;text-align:left;padding:7px 9px;font-size:10px;letter-spacing:.06em;text-transform:uppercase;color:#6B6256;border-bottom:1px solid #E3D8C6}
table.rt-tbl td{padding:7px 9px;border-bottom:1px solid #EFE7D9}
.rt-tot{margin-left:auto;width:48%}
.rt-tot td{padding:5px 9px}.rt-tot tr.grand td{border-top:2px solid #15212B;font-weight:700;font-size:14px}
.rt-terms{font-size:10px;color:#555;line-height:1.5;border-top:1px solid #E3D8C6;padding-top:10px;margin-top:14px}
.rt-sign{display:flex;justify-content:space-between;margin-top:40px}
.rt-sign div{width:42%;border-top:1px solid #15212B;padding-top:6px;font-size:11px;color:#6B6256}
.rt-stamp{display:inline-block;padding:4px 12px;border:2px solid #2E7D74;color:#2E7D74;border-radius:6px;font-weight:700;letter-spacing:.1em;transform:rotate(-4deg)}
